import React, { useState } from "react";
import {
  Home,
  CalendarDays,
  BookOpen,
  Users,
  UserRound,
  Mail,
  Settings,
  HelpCircle,
  Menu as MenuIcon,
  X as CloseIcon,
} from "lucide-react"; // npm install lucide-react

// Lista de menus
const menuItems = [
  { key: "dashboard", label: "Dashboard", icon: <Home size={24} /> },
  { key: "agendar", label: "Agendar Paciente", icon: <CalendarDays size={24} /> },
  { key: "disciplinas", label: "Disciplinas", icon: <BookOpen size={24} /> },
  { key: "pacientes", label: "Pacientes", icon: <Users size={24} /> },
  { key: "alunos", label: "Alunos", icon: <UserRound size={24} /> },
  { key: "periodos", label: "Períodos", icon: <Mail size={24} /> },
  { key: "solicitacoes", label: "Solicitações", icon: <Mail size={24} /> },
];

const bottomItems = [
  { key: "configuracoes", label: "Configurações", icon: <Settings size={24} /> },
  { key: "ajuda", label: "Ajuda", icon: <HelpCircle size={24} /> },
];

export default function Sidebar({ active, onMenuClick }) {
  const [open, setOpen] = useState(false);

  // Fechar Sidebar mobile ao clicar em link
  const handleMenuClick = (key) => {
    onMenuClick(key);
    setOpen(false);
  };

  return (
    <>
      {/* Botão de menu para mobile */}
      <button
        className="md:hidden fixed top-4 left-4 z-50 bg-[#3172C0] text-white p-2 rounded-full shadow"
        onClick={() => setOpen(true)}
        aria-label="Abrir menu"
      >
        <MenuIcon className="w-7 h-7" />
      </button>

      {/* Overlay escuro no mobile */}
      {open && (
        <div
          className="fixed inset-0 bg-black bg-opacity-40 z-40 md:hidden"
          onClick={() => setOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside
        className={`
          fixed top-0 left-0 z-50 h-full w-64 bg-white shadow-xl flex flex-col transition-transform duration-300
          ${open ? "translate-x-0" : "-translate-x-full"} 
          md:translate-x-0 md:static md:block
        `}
        style={{ minHeight: '100vh' }}
      >
        {/* Topo: logo/título */}
        <div className="text-2xl font-bold text-[#1d3557] p-6 border-b border-[#D9E0FF] relative">
          Meu App
          {/* Botão fechar só no mobile */}
          <button
            className="md:hidden absolute top-6 right-6 bg-gray-100 hover:bg-gray-200 text-[#1d3557] rounded-full p-2"
            onClick={() => setOpen(false)}
            aria-label="Fechar menu"
          >
            <CloseIcon className="w-6 h-6" />
          </button>
        </div>
        {/* Menu principal */}
        <nav className="flex-1 flex flex-col gap-1 mt-6">
          {menuItems.map(item => (
            <MenuItem
              key={item.key}
              icon={item.icon}
              label={item.label}
              active={active === item.key}
              onClick={() => handleMenuClick(item.key)}
            />
          ))}
        </nav>
        {/* Base: Config e Ajuda */}
        <div className="flex flex-col gap-1 mb-10 mt-4">
          {bottomItems.map(item => (
            <MenuItem
              key={item.key}
              icon={item.icon}
              label={item.label}
              active={active === item.key}
              onClick={() => handleMenuClick(item.key)}
            />
          ))}
        </div>
      </aside>
      {/* Espaço reservado no desktop para sidebar */}
      <div className="hidden md:block md:w-64" />
    </>
  );
}

// Componente de item do menu
function MenuItem({ icon, label, active, onClick }) {
  return (
    <button
      className={`flex items-center gap-3 py-3 px-6 rounded-full text-base transition-all ${
        active
          ? "bg-[#D9E0FF] text-[#23263A] font-bold shadow"
          : "text-[#23263A] hover:bg-gray-100"
      }`}
      onClick={onClick}
      style={{
        boxShadow: active
          ? "0px 2px 8px 0px rgba(100, 116, 139, 0.08) "
          : undefined,
      }}
    >
      <span>{icon}</span>
      {label}
    </button>
  );
}
